#include<bits/stdc++.h>
using namespace std;
long long a[300010],b[300010],sum[300010],blksiz,blk[300010],blkl[300010],blkr[300010],tag[300010];
int max1[300010],id[300010],flag[300010];
int cnt[610][300010],c[300010],p[610][610];
vector<int> mp[300010];
long long ans,tot;
long long calc(long long x,long long l,long long r)
{
    long long sum=upper_bound(mp[x].begin(),mp[x].end(),r)-lower_bound(mp[x].begin(),mp[x].end(),l);
    return sum;
}
int main()
{
    long long n;
    scanf("%lld",&n);
    blksiz=sqrt(n);
    long long blkcnt=0;
    for(long long i=1;blksiz*(i-1)+1<=n;i++)
    {
        blkcnt=i;
        blkl[i]=blksiz*(i-1)+1;
        blkr[i]=min(n,blksiz*i);
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        b[i]=a[i];
    }
    sort(b+1,b+1+n);
    for(long long i=1;i<=n;i++)
    {
        a[i]=lower_bound(b+1,b+1+n,a[i])-b;
    }
    for(long long i=1;i<=n;i++)
    {
        mp[a[i]].push_back(i);
        blk[i]=(i+blksiz-1)/blksiz;
        cnt[blk[i]][a[i]]++;
        max1[blk[i]]=max(max1[blk[i]],cnt[blk[i]][a[i]]);
        if(cnt[blk[i]][a[i]]==max1[blk[i]]&&(flag[blk[i]]==0||(flag[blk[i]]==1&&a[i]<id[blk[i]])))
        {
            flag[blk[i]]=1;
            id[blk[i]]=a[i];
        }
    }
    for(long long i=1;i<=blkcnt;i++)
    {
        memset(c,0,sizeof(c));
        long long now=-1;
        for(long long j=i;j<=blkcnt;j++)
        {
            for(long long k=blkl[j];k<=blkr[j];k++)
            {
                c[a[k]]++;
                if(now==-1||c[a[k]]>c[now]||(c[a[k]]==c[now]&&a[k]<now))
                {
                    now=a[k];
                }
            }
            p[i][j]=now;
        }
    }
    while(n--)
    {
        long long l,r;
        scanf("%lld%lld",&l,&r);
        ans=0,tot=0;
        if(blk[l]==blk[r])
        {
            for(long long i=l;i<=r;i++)
            {
                long long tmp=calc(a[i],l,r);
                if(tmp>tot||(tmp==tot&&a[i]<ans))
                {
                    ans=a[i];
                    tot=tmp;
                }
            }
            ans=b[ans];
            printf("%lld\n",ans);
            continue;
        }
        for(long long i=l;i<=blkr[blk[l]];i++)
        {
            long long tmp=calc(a[i],l,r);
            if(tmp>tot||(tmp==tot&&a[i]<ans))
            {
                ans=a[i];
                tot=tmp;
            }
        }
        for(long long i=blkl[blk[r]];i<=r;i++)
        {
            long long tmp=calc(a[i],l,r);
            if(tmp>tot||(tmp==tot&&a[i]<ans))
            {
                ans=a[i];
                tot=tmp;
            }
        }
        if(blk[l]+1!=blk[r])
        {
            long long tmp=calc(p[blk[l]+1][blk[r]-1],l,r);
            if(tmp>tot||(tmp==tot&&p[blk[l]+1][blk[r]-1]<ans))
            {
                ans=p[blk[l]+1][blk[r]-1];
                tot=tmp;
            }
        }
        ans=b[ans];
        printf("%lld\n",ans);
    }
    return 0;
}
